#include "rcv_p_rcv.h"

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

void rcv_p_rcv_initialize(void);
void rcv_p_rcv_notify(microkit_channel channel);
void rcv_p_rcv_timeTriggered(void);

volatile sb_queue_int32_t_1_t *in_val_queue_1;
sb_queue_int32_t_1_Recv_t in_val_recv_queue;
volatile sb_queue_uint8_t_1_t *evt_queue_1;
sb_queue_uint8_t_1_Recv_t evt_recv_queue;

#define PORT_FROM_MON 0

int32_t last_in_val_payload;

bool get_in_val(int32_t *data) {
  sb_event_counter_t numDropped;
  int32_t fresh_data;
  bool isFresh = sb_queue_int32_t_1_dequeue((sb_queue_int32_t_1_Recv_t *) &in_val_recv_queue, &numDropped, &fresh_data);
  if (isFresh) {
    last_in_val_payload = fresh_data;
  }
  *data = last_in_val_payload;
  return isFresh;
}

bool evt_is_empty(void) {
  return sb_queue_uint8_t_1_is_empty(&evt_recv_queue);
}

bool get_evt_poll(sb_event_counter_t *numDropped) {
  uint8_t eventPortPayload;
  uint8_t *data = &eventPortPayload;
  return sb_queue_uint8_t_1_dequeue((sb_queue_uint8_t_1_Recv_t *) &evt_recv_queue, numDropped, data);
}

bool get_evt() {
  sb_event_counter_t numDropped;
  return get_evt_poll (&numDropped);
}

void init(void) {
  printf("%s | INIT!\n", microkit_name);

  sb_queue_int32_t_1_Recv_init(&in_val_recv_queue, (sb_queue_int32_t_1_t *) in_val_queue_1);

  sb_queue_uint8_t_1_Recv_init(&evt_recv_queue, (sb_queue_uint8_t_1_t *) evt_queue_1);

  rcv_p_rcv_initialize();

  microkit_notify(PORT_FROM_MON);
}

void notified(microkit_channel channel) {
  switch (channel) {
    case PORT_FROM_MON:
      rcv_p_rcv_timeTriggered();
      break;
    default:
      rcv_p_rcv_notify(channel);
  }
}
